import{c as n,Q as a,j as t,m as p}from"./chunks/framework.Bhbi9jCp.js";const d=JSON.parse('{"title":"Web 渗透方法论:Burp Suite 工作流 / 手工 vs 自动化","description":"","frontmatter":{},"headers":[],"relativePath":"securityLearning/22-Web渗透方法论.md","filePath":"securityLearning/22-Web渗透方法论.md","lastUpdated":1778496697000}'),e={name:"securityLearning/22-Web渗透方法论.md"};function o(i,s,l,r,c,h){return a(),t("div",null,[...s[0]||(s[0]=[p(`<h1 id="web-渗透方法论-burp-suite-工作流-手工-vs-自动化" tabindex="-1">Web 渗透方法论:Burp Suite 工作流 / 手工 vs 自动化 <a class="header-anchor" href="#web-渗透方法论-burp-suite-工作流-手工-vs-自动化" aria-label="Permalink to &quot;Web 渗透方法论:Burp Suite 工作流 / 手工 vs 自动化&quot;">​</a></h1><p>上一篇讲完信息搜集——你已经知道目标有哪些资产、哪些子域、什么 web 服务、什么版本号。但<strong>列出资产不等于找到漏洞</strong>,真正的活在「点开第一个登录框之后」。这一篇讲清楚 Web 渗透工程师每天到底在干什么:<strong>不是&quot;一把梭工具&quot;,而是一套从抓包到改包到出报告的工业化流程</strong>。重点在「<strong>手工 vs 自动化的边界</strong>」——为什么 nuclei 跑完一遍只是热身,为什么 sqlmap 拿不到的注入资深工程师拿手工还能继续掏,为什么真正值钱的漏洞 90% 是业务逻辑漏洞、扫描器一辈子也扫不出来。</p><blockquote><p>一句话先记住:<strong>Web 渗透 = 把浏览器和服务器之间的对话彻底掌握在自己手里</strong>。Burp Suite 是&quot;代理 + 改包 + 重放&quot;的瑞士军刀,<strong>但它本身不会找漏洞——找漏洞的是你的大脑</strong>。自动化(ZAP / nuclei / sqlmap)只能扫&quot;模式化的洞&quot;(SQLi / XSS / 已知 CVE),<strong>业务逻辑漏洞(越权、薅羊毛、并发竞态、状态机绕过)永远要靠人</strong>——这也是为什么 HackerOne 上 5 万美金赏金的报告几乎都是逻辑洞,不是扫出来的。<strong>渗透的本质是&quot;把自己装进服务器开发者的脑子里&quot;,找他没想到的状态</strong>。</p></blockquote><hr><h2 id="一、先把三个词分清-渗透-扫描-红队" tabindex="-1">一、先把三个词分清:渗透 / 扫描 / 红队 <a class="header-anchor" href="#一、先把三个词分清-渗透-扫描-红队" aria-label="Permalink to &quot;一、先把三个词分清:渗透 / 扫描 / 红队&quot;">​</a></h2><p>工程师团队里这三个词经常混着用,但它们<strong>目标、产出、人手、时间窗都不一样</strong>——开口就糊,沟通会一直跑偏。</p><h3 id="_1-1-一张对比表" tabindex="-1">1.1 一张对比表 <a class="header-anchor" href="#_1-1-一张对比表" aria-label="Permalink to &quot;1.1 一张对比表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>漏洞扫描(VA)</th><th>渗透测试(Pentest)</th><th>红队演练(Red Team)</th></tr></thead><tbody><tr><td>目标</td><td>把已知漏洞列全</td><td>模拟攻击,验证可利用性</td><td>模拟真实攻击者,达成具体目标(拿到数据 / 入域)</td></tr><tr><td>人</td><td>工具为主,运维就能跑</td><td>渗透工程师 1-3 周</td><td>资深红队 4-12 周</td></tr><tr><td>范围</td><td>资产清单</td><td>明确 Scope 内的几个系统</td><td>全公司(物理 + 社工 + 0day 可能都用)</td></tr><tr><td>噪音</td><td>大(扫描器到处发包)</td><td>中(尽量不触发告警)</td><td>小(隐蔽,绕监控)</td></tr><tr><td>输出</td><td>CVE 列表 + CVSS</td><td>利用链 + 重现步骤 + 修复建议</td><td>攻击叙事 + 检测覆盖差距</td></tr><tr><td>蓝队是否知情</td><td>通常知情</td><td>通常知情</td><td><strong>不知情</strong>(Purple 除外)</td></tr></tbody></table><h3 id="_1-2-选型直觉" tabindex="-1">1.2 选型直觉 <a class="header-anchor" href="#_1-2-选型直觉" aria-label="Permalink to &quot;1.2 选型直觉&quot;">​</a></h3><ul><li><strong>每次发版后</strong>:跑漏扫(自动化、覆盖广、便宜)</li><li><strong>大版本上线 / 年度合规</strong>:做一次渗透(深度、有人脑)</li><li><strong>想知道&quot;真出事了你能不能扛&quot;</strong>:红队演练(贵、震撼,但能撬动管理层投入)</li></ul><blockquote><p>这一篇只讲<strong>渗透</strong>(Pentest)——上接漏扫(把&quot;可疑点&quot;留给人),下接红队(渗透是红队的子集,红队多了横向移动 / 内网 / 社工)。</p></blockquote><h3 id="_1-3-一个常见的误会-bug-bounty-pentest" tabindex="-1">1.3 一个常见的误会:Bug Bounty ≠ Pentest <a class="header-anchor" href="#_1-3-一个常见的误会-bug-bounty-pentest" aria-label="Permalink to &quot;1.3 一个常见的误会:Bug Bounty ≠ Pentest&quot;">​</a></h3><p>Bug Bounty 是<strong>众包式渗透</strong>(HackerOne / Bugcrowd / 阿里 SRC / 字节 SRC)——按规则提交漏洞拿赏金。<strong>Pentest 承诺覆盖率,BB 只承诺出洞付钱</strong>——所以两者互补,<strong>只做 BB 不做 Pentest 的公司迟早被一个没人愿意挖的功能背刺</strong>。</p><hr><h2 id="二、web-渗透的标准流程-四阶段" tabindex="-1">二、Web 渗透的标准流程:四阶段 <a class="header-anchor" href="#二、web-渗透的标准流程-四阶段" aria-label="Permalink to &quot;二、Web 渗透的标准流程:四阶段&quot;">​</a></h2><p>渗透不是&quot;扫一把然后随机戳&quot;。<strong>工业化流程是四步</strong>,每步的产出是下一步的输入。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Mapping(测绘)</span></span>
<span class="line"><span>   把目标的&quot;攻击面&quot;完整地画出来</span></span>
<span class="line"><span>   产出:URL 列表 + 参数 + 接口 + 角色 + 状态流转</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. Discovery(漏洞发现)</span></span>
<span class="line"><span>   对每个攻击面假设&quot;这里可能怎么坏&quot;</span></span>
<span class="line"><span>   产出:可疑点清单</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. Exploitation(漏洞利用)</span></span>
<span class="line"><span>   逐个验证可疑点,做出 PoC</span></span>
<span class="line"><span>   产出:可重现的利用链</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. Reporting(报告)</span></span>
<span class="line"><span>   把利用链转成开发能改、PM 能读、合规能存档的文档</span></span>
<span class="line"><span>   产出:漏洞报告</span></span></code></pre></div><p><strong>新手最大的错</strong>:跳过 Mapping 直接 Discovery——结果只测了登录页和首页几个明显的参数,<strong>90% 的攻击面根本没碰</strong>。<strong>Mapping 占整个渗透时间的 30-50% 是正常的</strong>。</p><h3 id="_2-1-mapping-把目标走一遍" tabindex="-1">2.1 Mapping:把目标走一遍 <a class="header-anchor" href="#_2-1-mapping-把目标走一遍" aria-label="Permalink to &quot;2.1 Mapping:把目标走一遍&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>被动测绘:挂上 Burp 代理,把目标当正常用户用一遍</span></span>
<span class="line"><span>  - 注册 / 登录 / 改密码 / 找回密码</span></span>
<span class="line"><span>  - 主流程从头到尾</span></span>
<span class="line"><span>  - 边缘功能:导出、上传、分享、订阅、通知</span></span>
<span class="line"><span>  - 不同角色全跑一遍(普通用户 / VIP / 管理员)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>主动测绘:</span></span>
<span class="line"><span>  - 目录爆破:dirsearch / ffuf,根据响应码筛</span></span>
<span class="line"><span>  - API 文档:Swagger / GraphQL Introspection 必查</span></span>
<span class="line"><span>  - 历史接口:JS 文件里翻出已下线但还能调的 URL</span></span>
<span class="line"><span>  - 子域接管:DNS 历史记录指向已释放的云资源</span></span></code></pre></div><p><strong>所有流量进 Burp</strong>——Mapping 阶段不要急着发漏洞,让 Burp 的 SiteMap 慢慢长出来。<strong>之后 Discovery 直接在这棵树上点</strong>,效率倍增。</p><h3 id="_2-2-discovery-对每个攻击面提假设" tabindex="-1">2.2 Discovery:对每个攻击面提假设 <a class="header-anchor" href="#_2-2-discovery-对每个攻击面提假设" aria-label="Permalink to &quot;2.2 Discovery:对每个攻击面提假设&quot;">​</a></h3><p>每碰到一个 URL,<strong>心里跑一遍假设模板</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>有 ID 参数(/order/123)?  → 越权(IDOR)/ ID 可枚举?</span></span>
<span class="line"><span>有上传?                  → 文件类型校验在哪做的?是黑名单还是白名单?</span></span>
<span class="line"><span>有跳转参数(redirect=)?  → 开放重定向 / SSRF?</span></span>
<span class="line"><span>有富文本?                → 存储型 XSS?</span></span>
<span class="line"><span>有搜索框?                → SQL / NoSQL / 模板注入?</span></span>
<span class="line"><span>有支付?                  → 价格 / 数量 / 币种能改?并发刷?</span></span>
<span class="line"><span>有限流?                  → 真的有限流 还是只在前端?</span></span>
<span class="line"><span>有 token?                 → JWT 算法能改?refresh 逻辑有没有漏?</span></span></code></pre></div><p><strong>这一步的核心是&quot;问问题&quot;</strong>——扫描器只问预设的几十种,人能问几百种,<strong>而且能根据业务上下文问</strong>(扫描器不知道这个 API 是支付接口)。</p><h3 id="_2-3-exploitation-验证-最小化-poc" tabindex="-1">2.3 Exploitation:验证 + 最小化 PoC <a class="header-anchor" href="#_2-3-exploitation-验证-最小化-poc" aria-label="Permalink to &quot;2.3 Exploitation:验证 + 最小化 PoC&quot;">​</a></h3><p>发现可疑点不等于漏洞——<strong>必须能稳定重现</strong>。 <strong>PoC 原则</strong>:</p><ul><li>最少的步骤:能 3 步重现的别用 5 步</li><li>最少的副作用:能用测试账号别动真账号</li><li>最小的危害展示:能证明&quot;读到 admin 的邮箱&quot;就够了,<strong>别真去删别人数据</strong></li></ul><blockquote><p>渗透的伦理边界:<strong>你证明能进就停</strong>,不是&quot;看看能不能拖库&quot;。</p></blockquote><h3 id="_2-4-reporting-让别人能改" tabindex="-1">2.4 Reporting:让别人能改 <a class="header-anchor" href="#_2-4-reporting-让别人能改" aria-label="Permalink to &quot;2.4 Reporting:让别人能改&quot;">​</a></h3><p>报告写得好,<strong>漏洞才会被修</strong>;写得烂,<strong>开发觉得&quot;扯淡&quot;就给你扔回来</strong>。详见第七节。</p><hr><h2 id="三、burp-suite-把浏览器和服务器的对话夺过来" tabindex="-1">三、Burp Suite:把浏览器和服务器的对话夺过来 <a class="header-anchor" href="#三、burp-suite-把浏览器和服务器的对话夺过来" aria-label="Permalink to &quot;三、Burp Suite:把浏览器和服务器的对话夺过来&quot;">​</a></h2><p>Burp 是 PortSwigger 出的<strong>收费工具</strong>(Community 版免费但很多功能锁了,Pro 版 ~$450/年),<strong>它是 Web 渗透事实上的工业标准</strong>——OWASP ZAP 是开源替代,功能类似但用得没那么爽。</p><h3 id="_3-1-核心模块速览" tabindex="-1">3.1 核心模块速览 <a class="header-anchor" href="#_3-1-核心模块速览" aria-label="Permalink to &quot;3.1 核心模块速览&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Proxy(代理)</span></span>
<span class="line"><span>    截下浏览器 ↔ 服务器的所有流量</span></span>
<span class="line"><span>    支持 Intercept(暂停每个请求)/ HTTP History(看历史)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Repeater(重放)</span></span>
<span class="line"><span>    挑一个请求,改一改,重发一次</span></span>
<span class="line"><span>    渗透 90% 的时间在这个模块</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Intruder(暴力 / 批量)</span></span>
<span class="line"><span>    把请求里某个位置替换成字典,批量发</span></span>
<span class="line"><span>    用于:爆密码 / 枚举 ID / Fuzz 参数</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Decoder(编解码)</span></span>
<span class="line"><span>    URL / Base64 / HTML / Hex 互转</span></span>
<span class="line"><span>    随手用,不是核心</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Comparer(对比)</span></span>
<span class="line"><span>    两个响应 diff 一下</span></span>
<span class="line"><span>    用于:看注入有没有触发&quot;不同行为&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Sequencer(随机性分析)</span></span>
<span class="line"><span>    采样一堆 token,看熵</span></span>
<span class="line"><span>    用于:session 是不是真随机</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Scanner(自动扫描,Pro 独占)</span></span>
<span class="line"><span>    把 Burp 当扫描器跑</span></span>
<span class="line"><span>    适合&quot;先粗扫再精修&quot;</span></span></code></pre></div><p><strong>90% 的时间用 Proxy + Repeater 这两个就够了</strong>。Intruder 用得对很猛,用不对会被风控秒封——后面会讲。</p><h3 id="_3-2-工作流-浏览器-→-proxy-→-repeater" tabindex="-1">3.2 工作流:浏览器 → Proxy → Repeater <a class="header-anchor" href="#_3-2-工作流-浏览器-→-proxy-→-repeater" aria-label="Permalink to &quot;3.2 工作流:浏览器 → Proxy → Repeater&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 浏览器配代理 127.0.0.1:8080,装 Burp 证书(解 HTTPS)</span></span>
<span class="line"><span>2. 正常使用目标网站</span></span>
<span class="line"><span>3. Proxy 的 HTTP History 里全是请求</span></span>
<span class="line"><span>4. 看到可疑的(比如 /api/order/123),右键 → Send to Repeater</span></span>
<span class="line"><span>5. 在 Repeater 里改包重发</span></span>
<span class="line"><span>6. 觉得这个洞稳了 → 截图 + 复制 raw 请求 → 进报告</span></span></code></pre></div><h3 id="_3-3-repeater-改包示例-授权环境" tabindex="-1">3.3 Repeater 改包示例(授权环境) <a class="header-anchor" href="#_3-3-repeater-改包示例-授权环境" aria-label="Permalink to &quot;3.3 Repeater 改包示例(授权环境)&quot;">​</a></h3><p>假设授权环境里有个个人信息 API:</p><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /api/user/profile?uid=1001 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">HTTP</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Host</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pentest-lab.local</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Cookie</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> session=eyJ1aWQiOjEwMDF9...</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">User-Agent</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Mozilla/5.0 ...</span></span></code></pre></div><p><strong>正常响应</strong>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;uid&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1001</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;alice&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;email&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;alice@example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>渗透假设</strong>:这里有没有越权?session 是 alice 的,uid 是 1001,<strong>如果我把 uid 改成 1002 呢</strong>?</p><p><strong>在 Repeater 里改一个字符</strong>:</p><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /api/user/profile?uid=1002 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">HTTP</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Host</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pentest-lab.local</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Cookie</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> session=eyJ1aWQiOjEwMDF9...</span></span></code></pre></div><p><strong>点 Send,看响应</strong>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;uid&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1002</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bob&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;email&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bob@example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>——拿 alice 的 session 读到了 bob 的资料。<strong>这是一个最经典的 IDOR(Insecure Direct Object Reference)漏洞</strong>,根因是 <code>WHERE uid = $param</code> 直接信任了 URL 参数,没和 session 里的 uid 做交叉校验。</p><blockquote><p>渗透 80% 的&quot;改包&quot;就这么简单——<strong>改一个参数,看响应变没变</strong>。值钱的不是改包,是「<strong>你能想到该改哪里</strong>」。</p></blockquote><h3 id="_3-4-intruder-批量改包但别滥用" tabindex="-1">3.4 Intruder:批量改包但别滥用 <a class="header-anchor" href="#_3-4-intruder-批量改包但别滥用" aria-label="Permalink to &quot;3.4 Intruder:批量改包但别滥用&quot;">​</a></h3><p>Intruder 把请求里你标的 <code>§位置§</code> 换成字典批量发——四个模式:<strong>Sniper</strong>(一变量一字典,经典爆密码)、<strong>Battering ram</strong>(多位置同字典)、<strong>Pitchfork</strong>(多位置各字典并行)、<strong>Cluster bomb</strong>(全组合)。<strong>风险</strong>:发包猛、特征明显,目标有 WAF / 风控基本秒封 IP。<strong>授权环境之外用 = 找死</strong>,而且大多数业务场景以为要爆破的其实可以靠逻辑漏洞绕过——<strong>别上来就硬刚</strong>。</p><h3 id="_3-5-burp-之外-mitmproxy-charles" tabindex="-1">3.5 Burp 之外:mitmproxy / Charles <a class="header-anchor" href="#_3-5-burp-之外-mitmproxy-charles" aria-label="Permalink to &quot;3.5 Burp 之外:mitmproxy / Charles&quot;">​</a></h3><p>Burp 是 Web 渗透主力;<strong>OWASP ZAP</strong> 是开源替代,CI/CD 集成强;<strong>mitmproxy</strong> 是命令行 / Python 脚本流,适合自定义重写或移动端;<strong>Charles</strong> 偏开发调试,渗透不够用。<strong>工程师做开发调试用 Charles 就够;一旦目标是&quot;找漏洞&quot;,装 Burp</strong>。</p><hr><h2 id="四、鉴权场景-不是改个-cookie-就完事" tabindex="-1">四、鉴权场景:不是改个 Cookie 就完事 <a class="header-anchor" href="#四、鉴权场景-不是改个-cookie-就完事" aria-label="Permalink to &quot;四、鉴权场景:不是改个 Cookie 就完事&quot;">​</a></h2><p>真实业务的鉴权远比&quot;贴 Cookie&quot;复杂——<strong>渗透工程师 30% 的时间在和鉴权斗智斗勇</strong>。</p><h3 id="_4-1-三种常见鉴权形态" tabindex="-1">4.1 三种常见鉴权形态 <a class="header-anchor" href="#_4-1-三种常见鉴权形态" aria-label="Permalink to &quot;4.1 三种常见鉴权形态&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Session Cookie(传统)</span></span>
<span class="line"><span>   登录后服务器返一个 Set-Cookie,后续请求自动带</span></span>
<span class="line"><span>   Burp 默认能处理,基本不操心</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. Bearer Token(JWT / OAuth)</span></span>
<span class="line"><span>   登录返一个 access_token,前端塞进 Authorization 头</span></span>
<span class="line"><span>   token 有过期时间,过了要 refresh</span></span>
<span class="line"><span>   Burp 默认不知道怎么刷,会一直发过期的</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 多步签名(签名 + 时间戳 + nonce)</span></span>
<span class="line"><span>   每个请求要算一个签名,签名包含时间戳</span></span>
<span class="line"><span>   时间戳过期 / nonce 重放都会被拒</span></span>
<span class="line"><span>   Burp 直接重发 99% 重放不了</span></span></code></pre></div><h3 id="_4-2-token-过期的处理" tabindex="-1">4.2 Token 过期的处理 <a class="header-anchor" href="#_4-2-token-过期的处理" aria-label="Permalink to &quot;4.2 Token 过期的处理&quot;">​</a></h3><p><strong>方案 A:手动刷</strong>——每隔几分钟重新登录,把新 token 粘进 Repeater。<strong>适合短时间精修一个洞</strong>,但 Intruder 跑 5000 个请求中途过期就废了。</p><p><strong>方案 B:Burp Session Handling Rules</strong>——配置一条规则:&quot;检测到 401 响应就自动跑一遍登录宏(Macro),把新 token 覆盖回当前请求&quot;。<strong>配好之后 Intruder 可以跑一整夜</strong>。</p><p><strong>方案 C:写 Burp 插件 / 用 mitmproxy 脚本</strong>——签名复杂(比如要从前端 JS 抠出算法)就只能写代码自动算签名 + 自动重发。<strong>这是渗透工程师和开发工程师能力交集最浓的一块</strong>。</p><h3 id="_4-3-multi-step-流程的处理" tabindex="-1">4.3 Multi-step 流程的处理 <a class="header-anchor" href="#_4-3-multi-step-流程的处理" aria-label="Permalink to &quot;4.3 Multi-step 流程的处理&quot;">​</a></h3><p>注册流程通常是「提交手机号 → 收验证码 → 提交验证码 → 设密码」四步。<strong>渗透时要测每一步的状态机</strong>:</p><ul><li>跳过第 2 步直接进第 3 步?</li><li>第 3 步的验证码能不能枚举?</li><li>第 4 步的&quot;哪个手机号要改密码&quot;是从 session 取的还是从前端传的?<strong>(前端传的 = 任意账户改密)</strong></li></ul><p><strong>Burp 的&quot;Engagement Tools → Macros&quot;能把多步流程录下来重放</strong>——但更多时候<strong>手工一步一步在 Repeater 里走</strong>,因为你要观察每一步的状态变化。</p><hr><h2 id="五、自动化的边界-nuclei-sqlmap-zap-能做什么不能做什么" tabindex="-1">五、自动化的边界:nuclei / sqlmap / ZAP 能做什么不能做什么 <a class="header-anchor" href="#五、自动化的边界-nuclei-sqlmap-zap-能做什么不能做什么" aria-label="Permalink to &quot;五、自动化的边界:nuclei / sqlmap / ZAP 能做什么不能做什么&quot;">​</a></h2><p>新手以为渗透就是&quot;挂上自动化工具点开始&quot;——<strong>走完一遍才发现自动化只是热身</strong>。</p><h3 id="_5-1-三类自动化工具" tabindex="-1">5.1 三类自动化工具 <a class="header-anchor" href="#_5-1-三类自动化工具" aria-label="Permalink to &quot;5.1 三类自动化工具&quot;">​</a></h3><table tabindex="0"><thead><tr><th>工具</th><th>擅长</th><th>不擅长</th></tr></thead><tbody><tr><td><strong>nuclei</strong></td><td>已知 CVE / 默认配置 / 信息泄漏(POC 模板化)</td><td>业务逻辑、需要登录的深层场景</td></tr><tr><td><strong>sqlmap</strong></td><td>SQL 注入的自动化利用(取数据 / 提权)</td><td>找注入点(它默认认为你已经知道哪里有注入)</td></tr><tr><td><strong>OWASP ZAP / Burp Scanner</strong></td><td>反射 XSS / 常见参数注入的初筛</td><td>多步业务、状态机、CSRF token 处理</td></tr><tr><td><strong>ffuf / dirsearch</strong></td><td>目录爆破 / 参数爆破</td><td>找&quot;有意义&quot;的目录(只会按字典硬扫)</td></tr></tbody></table><h3 id="_5-2-自动化能-开始-但不能-结束" tabindex="-1">5.2 自动化能&quot;开始&quot;,但不能&quot;结束&quot; <a class="header-anchor" href="#_5-2-自动化能-开始-但不能-结束" aria-label="Permalink to &quot;5.2 自动化能&quot;开始&quot;,但不能&quot;结束&quot;&quot;">​</a></h3><p><strong>nuclei 跑完</strong>——你可能拿到一堆&quot;暴露的 git 目录&quot;、&quot;低版本组件&quot;等信息泄漏。<strong>这些是入口,不是漏洞链</strong>——下一步要人来组装。</p><p><strong>sqlmap 跑通</strong>——你证明这个参数能注入,但<strong>怎么利用、能拿到哪张表、能不能写文件、能不能 RCE</strong>,需要你看着 dump 出的内容动脑判断。</p><p><strong>Burp Scanner 报&quot;可能存在 XSS&quot;</strong>——大多数时候是误报,<strong>真假要人去 Repeater 里验</strong>。</p><h3 id="_5-3-业务逻辑漏洞-自动化永远找不到" tabindex="-1">5.3 业务逻辑漏洞:自动化永远找不到 <a class="header-anchor" href="#_5-3-业务逻辑漏洞-自动化永远找不到" aria-label="Permalink to &quot;5.3 业务逻辑漏洞:自动化永远找不到&quot;">​</a></h3><p>这是渗透工程师最值钱的能力——<strong>理解业务,然后找业务&quot;不该有的状态&quot;</strong>。举几类自动化天然抓不到的:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>价格逻辑:</span></span>
<span class="line"><span>  下单接口 amount 字段可以改成负数?</span></span>
<span class="line"><span>  优惠券能不能并发用两张?</span></span>
<span class="line"><span>  退款金额能不能大于实付?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>权限越界:</span></span>
<span class="line"><span>  普通用户能调管理后台 API?(URL 没暴露不代表不存在)</span></span>
<span class="line"><span>  普通用户能改自己的角色字段?</span></span>
<span class="line"><span>  用户 A 的分享链接里有 token,token 没和 A 绑定?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>状态机绕过:</span></span>
<span class="line"><span>  实名认证流程能不能跳过&quot;上传身份证&quot;那一步?</span></span>
<span class="line"><span>  会员到期之后还能不能调 VIP 才有的接口?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>并发:</span></span>
<span class="line"><span>  签到接口连发 10 次能不能签到 10 天?</span></span>
<span class="line"><span>  抽奖接口能不能同一抽奖券中两次?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>数据导出:</span></span>
<span class="line"><span>  导出接口的&quot;导出范围&quot;能不能改成&quot;全公司&quot;?</span></span></code></pre></div><p><strong>为什么自动化抓不到</strong>:这些漏洞<strong>没有特征字符串、没有错误回显、响应码都是 200</strong>——扫描器看不出&quot;这个 200 是错的 200&quot;。<strong>只有读过业务文档、知道&quot;正常流程应该长什么样&quot;的人,才看得出&quot;现在这个流程不正常&quot;</strong>。</p><blockquote><p>这就是为什么 HackerOne 高赏金报告 70%+ 是逻辑洞——<strong>机器替代不了商业理解</strong>。</p></blockquote><h3 id="_5-4-一个常见的反例-别让-sqlmap-挂在生产" tabindex="-1">5.4 一个常见的反例:别让 sqlmap 挂在生产 <a class="header-anchor" href="#_5-4-一个常见的反例-别让-sqlmap-挂在生产" aria-label="Permalink to &quot;5.4 一个常见的反例:别让 sqlmap 挂在生产&quot;">​</a></h3><p>sqlmap 默认会发<strong>几千个测试 payload</strong>,很多带 <code>SLEEP(5)</code> 之类的时间盲注探测——<strong>对方数据库连接池可能直接被挂死</strong>。生产环境必须 <code>--risk=1 --level=1 --threads=1</code>,且明确单 URL <code>-u</code>,<strong>别用 <code>-m</code> 列表无脑跑</strong>。<strong>没授权别用,这条不商量</strong>。</p><hr><h2 id="六、为什么自动化代替不了人-三个心智" tabindex="-1">六、为什么自动化代替不了人:三个心智 <a class="header-anchor" href="#六、为什么自动化代替不了人-三个心智" aria-label="Permalink to &quot;六、为什么自动化代替不了人:三个心智&quot;">​</a></h2><p><strong>「假设」是人独有的</strong>。扫描器只能找字典里有的洞;<strong>新型 / 奇怪的业务洞 / 组合利用,都需要人提&quot;如果……会怎样&quot;的假设</strong>。扫描器看到一个参数只问&quot;加 <code>&#39;</code> 报错吗&quot;,渗透会问:这是订单号能换成别人的吗?是数字传负数 / 超大数 / 0 会怎样?是 UUID 用 v1(可预测时间戳)会怎样?</p><p><strong>「组合」是人独有的</strong>。单点 CVSS 可能很低,<strong>组合起来变成致命链</strong>:「任意用户邮箱可枚举(低)」+「找回密码 4 位验证码不限速(低)」+「session 不绑 IP/UA(低)」= 任意账户接管(关键)。<strong>扫描器不会组合</strong>,渗透工程师会把三条串起来配攻击叙事——这就是为什么手工渗透比扫描器发现&quot;值钱十倍&quot;。</p><p><strong>「修复建议」是人独有的</strong>。扫描器对所有 XSS 都给&quot;过滤特殊字符&quot;——<strong>等于没说</strong>。人写的应该是:「短期:<code>templates/order.html:47</code> 的 <code>{{name}}</code> 改 <code>{{name|escape}}</code>;长期:全站开 Jinja2 autoescape,删 <code>config.py</code> 里 <code>autoescape=False</code>;监测:WAF 加规则对含 <code>&lt;script</code> 的 POST 告警(只告警先看误报)」。<strong>带代码行号开发当晚就改;通用模板开发拖一个月</strong>。</p><hr><h2 id="七、漏洞报告写作-让别人愿意修" tabindex="-1">七、漏洞报告写作:让别人愿意修 <a class="header-anchor" href="#七、漏洞报告写作-让别人愿意修" aria-label="Permalink to &quot;七、漏洞报告写作:让别人愿意修&quot;">​</a></h2><p>漏洞报告是渗透工程师<strong>最重要的产出</strong>——不是 PoC 文件夹,<strong>是一份能让 PM 看懂、开发能改、合规能存档的文档</strong>。</p><h3 id="_7-1-模板-六段式" tabindex="-1">7.1 模板:六段式 <a class="header-anchor" href="#_7-1-模板-六段式" aria-label="Permalink to &quot;7.1 模板:六段式&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 标题</span></span>
<span class="line"><span>   [严重] 订单接口越权读取 - /api/order/{id} 缺少所属人校验</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 严重程度</span></span>
<span class="line"><span>   CVSS 3.1: 7.5 (High)</span></span>
<span class="line"><span>   CVSS 向量: AV:N/AC:L/PR:L/UI:N/S:U/C:H/I:N/A:N</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 影响</span></span>
<span class="line"><span>   - 一个登录的普通用户可枚举所有订单</span></span>
<span class="line"><span>   - 影响约 200 万存量订单的隐私</span></span>
<span class="line"><span>   - 包含金额、地址、商品 SKU、配送电话</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 重现步骤(给 QA 看)</span></span>
<span class="line"><span>   a) 用测试账号 A(uid=10001)登录,获取 session</span></span>
<span class="line"><span>   b) 在 Burp Repeater 中发起以下请求:</span></span>
<span class="line"><span>      GET /api/order/99999 HTTP/1.1</span></span>
<span class="line"><span>      Cookie: session=...A...</span></span>
<span class="line"><span>   c) 观察响应:返回订单 99999 的完整信息,</span></span>
<span class="line"><span>      但订单 99999 属于 uid=20002,不是 A 的</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 修复建议(给 RD 看)</span></span>
<span class="line"><span>   短期:</span></span>
<span class="line"><span>     在 OrderController.java 第 87 行的查询前加:</span></span>
<span class="line"><span>     if (order.getUserId() != session.getUserId()) {</span></span>
<span class="line"><span>         throw new ForbiddenException();</span></span>
<span class="line"><span>     }</span></span>
<span class="line"><span>   长期:</span></span>
<span class="line"><span>     全局加 @AuthorizeOwner 注解 + AOP 校验</span></span>
<span class="line"><span>     在 service 层禁止直接用 URL 来的 id 查,统一从 SecurityContext 取</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. 参考</span></span>
<span class="line"><span>   OWASP A01:2021 Broken Access Control</span></span>
<span class="line"><span>   CWE-639 Authorization Bypass Through User-Controlled Key</span></span></code></pre></div><h3 id="_7-2-三个让报告被快速修的小技巧" tabindex="-1">7.2 三个让报告被快速修的小技巧 <a class="header-anchor" href="#_7-2-三个让报告被快速修的小技巧" aria-label="Permalink to &quot;7.2 三个让报告被快速修的小技巧&quot;">​</a></h3><p><strong>贴截图,但要打码</strong>——浏览器开发者工具截图比&quot;原始 burp 截图&quot;对 PM 友好十倍,<strong>但敏感字段(真实姓名、手机号)一定要打码</strong>。</p><p><strong>给出预期 vs 实际</strong>——「应该返回 403,实际返回了 200 + 完整数据」,<strong>开发立刻知道改的方向</strong>。</p><p><strong>带视频更好</strong>——5-10 秒的录屏(用 macOS 自带录屏即可),<strong>比 20 行文字 PoC 更让人懂</strong>。</p><h3 id="_7-3-cvss-怎么用-怎么别滥用" tabindex="-1">7.3 CVSS:怎么用,怎么别滥用 <a class="header-anchor" href="#_7-3-cvss-怎么用-怎么别滥用" aria-label="Permalink to &quot;7.3 CVSS:怎么用,怎么别滥用&quot;">​</a></h3><p>CVSS 3.1 是<strong>通用打分系统</strong>——8 个维度算出一个 0-10 的分。但<strong>它有两个常见误用</strong>:</p><ol><li><strong>算出来分高就当严重</strong>——CVSS 里&quot;远程未授权 RCE&quot;和&quot;远程未授权读个公开版本号&quot;都可能算出 7+ 分,<strong>实际影响差几万倍</strong>。<strong>用 CVSS 做参考,不用 CVSS 做结论</strong>。</li><li><strong>业务上下文没纳入</strong>——CVSS 不知道这个系统是核心支付还是边缘运营后台。<strong>报告里同时写 CVSS 分数 + 一句业务影响</strong>(「核心交易链路,出事影响 GMV」),决策会更准。</li></ol><blockquote><p>真实做法:<strong>CVSS 给一个分,然后用公司内部的&quot;业务影响&quot;维度再校准一次</strong>——通常以 P0/P1/P2/P3 表达。</p></blockquote><h3 id="_7-4-一份好报告-vs-一份烂报告" tabindex="-1">7.4 一份好报告 vs 一份烂报告 <a class="header-anchor" href="#_7-4-一份好报告-vs-一份烂报告" aria-label="Permalink to &quot;7.4 一份好报告 vs 一份烂报告&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>烂:  这个接口有 SQL 注入</span></span>
<span class="line"><span>好:  GET /search?q=&#39; UNION SELECT 1,2,3-- 返回 mysql 版本 8.0.31,</span></span>
<span class="line"><span>     说明此处 UNION 注入。能拖 users 表(200w 行,bcrypt password_hash)。</span></span>
<span class="line"><span>     根因:SearchController.java:42 用字符串拼接,没用 PreparedStatement。</span></span>
<span class="line"><span>     修复:改 PreparedStatement.setString(1, &quot;%&quot; + q + &quot;%&quot;)。</span></span>
<span class="line"><span>     纵深:全站接入参数化 ORM(MyBatis 已在用,此接口走的裸 JDBC);</span></span>
<span class="line"><span>          WAF 加搜索接口 q 参数含 UNION/SELECT 告警(只告警,先看误报)。</span></span></code></pre></div><p><strong>烂报告浪费所有人时间;好报告省一周排期,让你下次还能被请回来</strong>。</p><hr><h2 id="八、法律红线-授权范围与-rules-of-engagement" tabindex="-1">八、法律红线:授权范围与 Rules of Engagement <a class="header-anchor" href="#八、法律红线-授权范围与-rules-of-engagement" aria-label="Permalink to &quot;八、法律红线:授权范围与 Rules of Engagement&quot;">​</a></h2><p><strong>这一节最短,但是最重要</strong>——所有技术能力都建立在&quot;合法授权&quot;之上,<strong>没授权的渗透就是非法访问计算机信息系统罪</strong>(中国《刑法》第 285 条,<strong>3 年起步</strong>)。</p><h3 id="_8-1-scope-必须白纸黑字" tabindex="-1">8.1 Scope 必须白纸黑字 <a class="header-anchor" href="#_8-1-scope-必须白纸黑字" aria-label="Permalink to &quot;8.1 Scope 必须白纸黑字&quot;">​</a></h3><p>口头授权 = 没授权。<strong>必须有书面文档</strong>,内容至少包含:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 授权人(法定代表人 / 安全负责人)及其权限证明</span></span>
<span class="line"><span>2. 测试目标的精确范围</span></span>
<span class="line"><span>   - 哪些域名 / IP / 端口</span></span>
<span class="line"><span>   - 哪些不在范围内</span></span>
<span class="line"><span>   - 子域是否包含(&quot;通配&quot;还是&quot;精确列表&quot;)</span></span>
<span class="line"><span>3. 测试时间窗口</span></span>
<span class="line"><span>   - 起止日期</span></span>
<span class="line"><span>   - 每天的可测试小时段</span></span>
<span class="line"><span>4. 允许的测试手法</span></span>
<span class="line"><span>   - 自动化扫描是否允许</span></span>
<span class="line"><span>   - 拒绝服务测试是否允许</span></span>
<span class="line"><span>   - 数据库导出是否允许</span></span>
<span class="line"><span>5. 禁止的行为</span></span>
<span class="line"><span>   - 不得动用社工 / 物理入侵</span></span>
<span class="line"><span>   - 不得使用真实生产数据</span></span>
<span class="line"><span>   - 不得对外披露</span></span>
<span class="line"><span>6. 紧急联系人(出事时立即通知谁)</span></span>
<span class="line"><span>7. 法律条款(责任界定)</span></span></code></pre></div><h3 id="_8-2-rules-of-engagement-roe" tabindex="-1">8.2 Rules of Engagement(RoE) <a class="header-anchor" href="#_8-2-rules-of-engagement-roe" aria-label="Permalink to &quot;8.2 Rules of Engagement(RoE)&quot;">​</a></h3><p>Scope 是&quot;能测什么&quot;,<strong>RoE 是&quot;怎么测&quot;</strong>:</p><ul><li>发现高危漏洞是否要<strong>立即停手</strong>通知?</li><li>拿到生产数据是否<strong>立即销毁</strong>?</li><li>是否允许<strong>留后门验证持久化</strong>?(99% 的情况下:不允许)</li><li>出事后<strong>日志保留义务</strong>(你的 burp 日志通常要保 6 个月以上)</li></ul><blockquote><p>这一行的老话:<strong>&quot;先把合同签了再开 Burp&quot;</strong>。<strong>没合同别敲第一个回车</strong>。</p></blockquote><h3 id="_8-3-几个常见的-以为是灰色实际是黑色-的场景" tabindex="-1">8.3 几个常见的&quot;以为是灰色实际是黑色&quot;的场景 <a class="header-anchor" href="#_8-3-几个常见的-以为是灰色实际是黑色-的场景" aria-label="Permalink to &quot;8.3 几个常见的&quot;以为是灰色实际是黑色&quot;的场景&quot;">​</a></h3><ul><li><strong>&quot;朋友说他公司的网站给我测&quot;</strong>——朋友不是法定代表人,无效。</li><li><strong>&quot;网站没有禁止扫描的声明所以我可以扫&quot;</strong>——错,<strong>没禁止 ≠ 允许</strong>。</li><li><strong>&quot;先扫一下看有没有洞,有再去申请授权&quot;</strong>——错,<strong>扫描动作本身就构成非法访问</strong>。</li><li><strong>&quot;我用自己注册的账号测,所以是测我自己的数据&quot;</strong>——错,<strong>只要发包到对方服务器,行为本身就受授权约束</strong>。</li><li><strong>&quot;BB 项目挂出来了我直接开测&quot;</strong>——<strong>先读完它的 Policy</strong>,99% 的 BB 项目有明确的 in-scope / out-of-scope / 禁止手法清单。</li></ul><h3 id="_8-4-渗透前需要拿到的授权清单" tabindex="-1">8.4 渗透前需要拿到的授权清单 <a class="header-anchor" href="#_8-4-渗透前需要拿到的授权清单" aria-label="Permalink to &quot;8.4 渗透前需要拿到的授权清单&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>□ 书面授权合同(含双方法定代表人签字 + 公章)</span></span>
<span class="line"><span>□ Scope 文档(域名 / IP / 端口的精确列表)</span></span>
<span class="line"><span>□ 测试时间窗(起止日期 + 每日可测试时段)</span></span>
<span class="line"><span>□ RoE(允许的手法 / 禁止的手法 / 高危发现的处置流程)</span></span>
<span class="line"><span>□ 紧急联系人电话(7×24 可达 2 个以上)</span></span>
<span class="line"><span>□ 测试账号(明确属于渗透测试用,不要复用员工真账号)</span></span>
<span class="line"><span>□ 内部告知函(目标方运维 / 风控 / WAF 团队知晓本次测试)</span></span>
<span class="line"><span>□ 出口 IP 报备(你的测试 IP 加白,避免 WAF 拦你)</span></span>
<span class="line"><span>□ 数据处理协议(渗透过程中接触的数据如何销毁)</span></span>
<span class="line"><span>□ 保密协议(NDA,渗透发现的漏洞不得对外披露)</span></span>
<span class="line"><span>□ 法律意见书(目标涉及金融 / 关基行业时建议)</span></span>
<span class="line"><span>□ 漏洞披露条款(报告交付期 / 修复后多久允许写 blog / 演讲)</span></span></code></pre></div><p><strong>全打勾再开 Burp</strong>。少一条就回去补,<strong>别&quot;今天先开始,合同明天补&quot;</strong>——一旦出事这就是关键证据。</p><hr><h2 id="九、真实案例-能从公开报告学到什么" tabindex="-1">九、真实案例:能从公开报告学到什么 <a class="header-anchor" href="#九、真实案例-能从公开报告学到什么" aria-label="Permalink to &quot;九、真实案例:能从公开报告学到什么&quot;">​</a></h2><p><strong>不去看具体的 payload,看&quot;思路是怎么展开的&quot;</strong>——这是最快的进步方式。</p><p><strong>HackerOne 高分报告</strong>(hackerone.com/hacktivity)几乎都是业务逻辑漏洞,结构稳定:简短背景 → 正常流程截图 → 在哪一步发现&quot;不太对&quot; → 完整利用链 → 影响范围 → 修复建议(开发能直接抄的级别)。<strong>模仿这个结构写公司内的报告,可读性立刻提一档</strong>。</p><p><strong>国内 SRC</strong>(阿里 / 字节)高分报告偏组合利用:单点都是低危,组合起来是高危;报告里画攻击链图、主动给修复 diff、附业务影响估算(影响 X 用户 / Y 资金)。<strong>学这些公开报告比刷&quot;100 个 XSS payload&quot;性价比高得多——payload 几年就过时,方法论十年还能用</strong>。</p><p><strong>反面教训</strong>:新手报告爱写「我用了非常巧妙的 oneliner 拿到 RCE」——<strong>审报告的人不关心你巧妙</strong>,关心漏洞、影响、怎么修。<strong>炫技放 blog,不放进生产报告</strong>。</p><hr><h2 id="十、踩坑提醒" tabindex="-1">十、踩坑提醒 <a class="header-anchor" href="#十、踩坑提醒" aria-label="Permalink to &quot;十、踩坑提醒&quot;">​</a></h2><ol><li><strong>跳过 Mapping 直接撸接口</strong>——80% 的攻击面没碰过,出报告时尴尬到死</li><li><strong>Burp 不装证书也不知道为什么 HTTPS 抓不到</strong>——配代理之后必须装 CA 证书到系统/浏览器</li><li><strong>Intruder 不挂限速直接开 200 线程</strong>——目标 WAF 5 秒封 IP,接下来一天没法测</li><li><strong>拿 sqlmap 跑生产</strong>——拖死库可能要负民事甚至刑事责任</li><li><strong>token 过期没自动续期</strong>——Intruder 跑了 6 小时全是 401</li><li><strong>扫到一堆漏洞但不会写报告</strong>——开发不修,等于白干</li><li><strong>Scope 没看清就开测</strong>——一个回车进了禁止范围 = 法律风险</li><li><strong>以为自动化能取代人</strong>——业务逻辑漏洞这条路只能人走</li><li><strong>不留 burp 工程文件</strong>——出事时拿不出&quot;我当时具体测了什么&quot;的证据</li><li><strong>PoC 写得太花哨</strong>——开发看不懂就不修,你的漏洞等于没找</li></ol><hr><h2 id="十一、心态-渗透是-换位思考-的极致" tabindex="-1">十一、心态:渗透是&quot;换位思考&quot;的极致 <a class="header-anchor" href="#十一、心态-渗透是-换位思考-的极致" aria-label="Permalink to &quot;十一、心态:渗透是&quot;换位思考&quot;的极致&quot;">​</a></h2><p>写完这一篇,你应该明白渗透不是&quot;会几个工具&quot;,<strong>渗透是一种思维方式</strong>——看到登录框先想&quot;我会怎么实现&quot;,看到支付接口先想&quot;如果是我写会忘记校验什么&quot;,看到文件上传先想&quot;黑白名单各漏什么&quot;,看到状态机先想&quot;跳过中间一步会进入什么不可达状态&quot;。<strong>渗透工程师的本质是&quot;反向开发&quot;</strong>——在脑子里重建对方系统的实现,然后找实现的破绽。<strong>所以最好的渗透工程师往往是写过同类系统的人</strong>——&quot;开发 + 安全双背景&quot;在市场上最贵。</p><blockquote><p><strong>写代码的时候多想一步&quot;这里会被怎么打&quot;</strong>,你不一定要去做渗透,<strong>但这种本能能让你写的代码安全度高一个数量级</strong>——这就是这个系列想给读者建立的&quot;被攻击的本能&quot;。</p></blockquote><hr><p>下一篇:<code>23-内网渗透.md</code>,讲渗透工程师拿到第一台机器之后的接下来 30 步——横向移动、权限提升、Pass-the-Hash、Kerberoasting、域控接管、C2 流量隐藏。<strong>Web 渗透是边界突破,内网渗透是&quot;进城之后&quot;</strong>——两套完全不同的方法论。</p>`,135)])])}const u=n(e,[["render",o]]);export{d as __pageData,u as default};
